import React, { useEffect, useState, useCallback, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { phongAPI, yeuCauAPI, thanhToanAPI } from '../services/api';
import { buildPhongAddress } from '../utils/location';
import './QuanLyPhong.css';

const fmt = (n) => 
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);


const DotIcon = React.memo(() => (
  <svg viewBox="0 0 24 24" aria-hidden="true">
    <circle cx="6" cy="12" r="1.9" fill="currentColor" />
    <circle cx="12" cy="12" r="1.9" fill="currentColor" />
    <circle cx="18" cy="12" r="1.9" fill="currentColor" />
  </svg>
));

const MemberRow = React.memo(({ member, phong, onOpenMenu, memberMenu, onDeleteMember }) => {
  const isMenuOpen = memberMenu?.maPhong === phong.maPhong && 
                     memberMenu?.maThanhVien === member.maNguoiDung;

  return (
    <div className="member-row">
      <Link 
        to={`/nguoi-dung/${member.maNguoiDung}`} 
        className="member-profile-link member-row-link"
      >
        <img
          src={member.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(member.hoTen)}&background=12355B&color=fff&size=40`}
          className="avatar avatar-sm"
          alt={member.hoTen}
          loading="lazy"
        />
        <div className="member-row-text">
          <strong>{member.hoTen}</strong>
          <span>
            {member.ngayThamGia 
              ? `Vào phòng: ${new Date(member.ngayThamGia).toLocaleDateString('vi-VN')}` 
              : 'Thành viên hiện tại'}
          </span>
        </div>
      </Link>

      <div className="member-menu-wrap">
        <button
          type="button"
          className="member-menu-trigger"
          onClick={() => onOpenMenu(phong.maPhong, member.maNguoiDung)}
        >
          <DotIcon />
        </button>

        {isMenuOpen && (
          <div className="member-menu-dropdown">
            <button 
              type="button" 
              className="member-menu-item"
              onClick={() => onDeleteMember(phong.maPhong, member.maNguoiDung)}
            >
              Xóa thành viên
            </button>
          </div>
        )}
      </div>
    </div>
  );
});

const RoomCard = React.memo(({ 
  phong, 
  selectedPhong, 
  yeuCaus, 
  memberMenu,
  deletingPhongId,
  onToggleYeuCau,
  onDeletePhong,
  onChangeStatus,
  onDeleteMember,
  onOpenMemberMenu,
  onChiaTuDong,
  onNavigate 
}) => {
  const yeuCauList = yeuCaus[phong.maPhong] || [];

  return (
    <div className="card phong-manage-card">
      <div className="phong-manage-header">
        <div>
          <h3>{phong.title}</h3>
          <div className="phong-manage-subtitle">
            {buildPhongAddress(phong)} · {fmt(phong.giaTien)}/thang
          </div>
        </div>

        <div className="phong-manage-header-actions">
          <span className={`badge ${
            phong.trangThai === 'San sang' ? 'badge-success' :
            phong.trangThai === 'Da day' ? 'badge-danger' : 'badge-warning'
          }`}>
            {phong.trangThai === 'San sang' ? 'Sẵn sàng' : 
             phong.trangThai === 'Da day' ? 'Đầy' : 'Bảo trì'}
          </span>

          <select
            className="form-control phong-status-select"
            value={phong.trangThai}
            onChange={(e) => onChangeStatus(phong.maPhong, e.target.value)}
          >
            <option value="San sang">Sẵn sàng</option>
            <option value="Da day">Đầy</option>
            <option value="Bao tri">Bảo trì</option>
          </select>
        </div>
      </div>

      <div className="phong-manage-body">
        <div className="phong-manage-main">
          <div className="room-cost-grid">
            <div className="room-cost-card"><span>Giá phòng</span><strong>{fmt(phong.giaTien)}/thang</strong></div>
            <div className="room-cost-card"><span>Tiền dịch vụ</span><strong>{fmt(phong.tienDichVu)}</strong></div>
            <div className="room-cost-card"><span>Tiền điện</span><strong>{fmt(phong.tienDien)}</strong></div>
            <div className="room-cost-card"><span>Tiền nước</span><strong>{fmt(phong.tienNuoc)}</strong></div>
          </div>

          <div className="members-section">
            <h4>Thành viên phòng ({phong.soNguoiHienTai}/{phong.soNguoiToiDa})</h4>
            <div className="members-list-column">
              {phong.danhSachThanhVien?.length > 0 ? (
                phong.danhSachThanhVien.map(member => (
                  <MemberRow
                    key={member.maNguoiDung}
                    member={member}
                    phong={phong}
                    memberMenu={memberMenu}
                    onOpenMenu={onOpenMemberMenu}
                    onDeleteMember={onDeleteMember}
                  />
                ))
              ) : (
                <p className="member-empty">Chưa có thành viên</p>
              )}
            </div>
          </div>
        </div>

        <div className="phong-actions">
          <button className="btn btn-outline btn-sm" onClick={() => onNavigate(`/phong/${phong.maPhong}`)}>
            Xem chi tiết
          </button>
          <button className="btn btn-outline btn-sm" onClick={() => onNavigate(`/phong/${phong.maPhong}/chinh-sua`)}>
            Chỉnh sửa
          </button>
          <button 
            className="btn btn-secondary btn-sm" 
            onClick={() => onToggleYeuCau(phong.maPhong)}
          >
            {selectedPhong === phong.maPhong ? 'Ẩn yêu cầu' : 'Xem yêu cầu'}
          </button>
          <button className="btn btn-success btn-sm" onClick={() => onChiaTuDong(phong.maPhong)}>
            Chia tự động
          </button>
          <button 
            className="btn btn-danger btn-sm" 
            onClick={() => onDeletePhong(phong.maPhong)}
            disabled={deletingPhongId === phong.maPhong}
          >
            {deletingPhongId === phong.maPhong ? 'Đang xóa...' : 'Xóa phòng'}
          </button>
        </div>
      </div>

      {selectedPhong === phong.maPhong && (
        <div className="yeu-cau-panel">
          <h4>Yêu cầu tham gia</h4>
          {yeuCauList.length === 0 ? (
            <p className="member-empty">Chưa có yêu cầu nào.</p>
          ) : (
            yeuCauList.map(yc => (
              <div key={yc.maYeuCau} className="yeu-cau-item">
                {/* ... phần hiển thị yêu cầu giữ nguyên như cũ ... */}
                <Link to={`/nguoi-dung/${yc.maNguoiDung}`} className="yeu-cau-user-link">
                  <img
                    src={yc.avatarNguoiDung || `https://ui-avatars.com/api/?name=${encodeURIComponent(yc.tenNguoiDung)}&size=40`}
                    className="avatar avatar-sm"
                    alt={yc.tenNguoiDung}
                    loading="lazy"
                  />
                  <div style={{ flex: 1 }}>
                    <strong>{yc.tenNguoiDung}</strong>
                    {yc.moTa && <p className="yeu-cau-note">{yc.moTa}</p>}
                  </div>
                </Link>
                <span className={`badge ${yc.trangThai === 'Chap nhan' ? 'badge-success' : yc.trangThai === 'Tu choi' ? 'badge-danger' : 'badge-warning'}`}>
                  {yc.trangThai === 'Chap nhan' ? 'Đã chấp nhận' : yc.trangThai === 'Tu choi' ? 'Đã từ chối' : 'Chờ duyệt'}
                </span>
                {yc.trangThai === 'Cho duyet' && (
                  <div className="yeu-cau-action-row">
                    <button className="btn btn-success btn-sm" onClick={() => handleDuyet(yc.maYeuCau, true, phong.maPhong)}>
                      Duyệt
                    </button>
                    <button className="btn btn-danger btn-sm" onClick={() => handleDuyet(yc.maYeuCau, false, phong.maPhong)}>
                      Từ chối
                    </button>
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
});

// ====================== MAIN COMPONENT ======================

export default function QuanLyPhong() {
  const navigate = useNavigate();

  const [phongs, setPhongs] = useState([]);
  const [phongThamGia, setPhongThamGia] = useState([]);
  const [yeuCaus, setYeuCaus] = useState({});
  const [selectedPhong, setSelectedPhong] = useState(null);
  const [loading, setLoading] = useState(true);
  const [deletingPhongId, setDeletingPhongId] = useState(null);
  const [memberMenu, setMemberMenu] = useState(null);

  // Fetch data
  const fetchPhongs = useCallback(async () => {
    setLoading(true);
    try {
      const [ownedRes, joinedRes] = await Promise.all([
        phongAPI.layPhongCuaToi(),
        phongAPI.layPhongThamGia().catch(() => ({ data: { data: [] } })),
      ]);
      setPhongs(ownedRes.data.data || []);
      setPhongThamGia(joinedRes.data.data || []);
    } catch (err) {
      toast.error('Không tải được danh sách phòng');
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchYeuCau = useCallback(async (maPhong) => {
    try {
      const res = await yeuCauAPI.layCuaPhong(maPhong);
      setYeuCaus(prev => ({ ...prev, [maPhong]: res.data.data || [] }));
    } catch {
      toast.error('Không tải được yêu cầu tham gia');
    }
  }, []);

  useEffect(() => {
    fetchPhongs();
  }, [fetchPhongs]);

  // Event handlers được memoized
  const handleDuyet = useCallback(async (maYeuCau, chapNhan, maPhong) => {
    try {
      await yeuCauAPI.duyet(maYeuCau, chapNhan);
      toast.success(chapNhan ? 'Đã chấp nhận yêu cầu' : 'Đã từ chối yêu cầu');
      fetchPhongs();
      fetchYeuCau(maPhong);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  }, [fetchPhongs, fetchYeuCau]);

  const handleChiaTuDong = useCallback(async (maPhong) => {
    try {
      await thanhToanAPI.chiaTien(maPhong);
      toast.success('Đã chia tự động thành công');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  }, []);

  const handleXoaThanhVien = useCallback(async (maPhong, maThanhVien) => {
    if (!window.confirm('Bạn có chắc muốn xóa thành viên này khỏi phòng không?')) return;

    try {
      await phongAPI.xoaThanhVien(maPhong, maThanhVien);
      toast.success('Đã xóa thành viên khỏi phòng');
      setMemberMenu(null);
      fetchPhongs();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa thành viên thất bại');
    }
  }, [fetchPhongs]);

  const handleDoiTrangThai = useCallback(async (maPhong, trangThai) => {
    try {
      await phongAPI.capNhat(maPhong, { trangThai });
      toast.success('Cập nhật trạng thái thành công');
      fetchPhongs();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Thất bại');
    }
  }, [fetchPhongs]);

  const handleDeletePhong = useCallback(async (maPhong) => {
    if (!window.confirm('Bạn có chắc muốn xóa phòng này không?')) return;

    setDeletingPhongId(maPhong);
    try {
      await phongAPI.xoa(maPhong);

      setPhongs(prev => prev.filter(p => p.maPhong !== maPhong));
      setSelectedPhong(prev => prev === maPhong ? null : prev);

      setYeuCaus(prev => {
        const next = { ...prev };
        delete next[maPhong];
        return next;
      });

      toast.success('Đã xóa phòng thành công');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Xóa phòng thất bại');
    } finally {
      setDeletingPhongId(null);
    }
  }, []);

  const handleToggleYeuCau = useCallback((maPhong) => {
    if (selectedPhong === maPhong) {
      setSelectedPhong(null);
    } else {
      setSelectedPhong(maPhong);
      fetchYeuCau(maPhong);
    }
  }, [selectedPhong, fetchYeuCau]);

  const handleOpenMemberMenu = useCallback((maPhong, maThanhVien) => {
    setMemberMenu(prev => 
      prev?.maPhong === maPhong && prev?.maThanhVien === maThanhVien 
        ? null 
        : { maPhong, maThanhVien }
    );
  }, []);

  const handleNavigate = useCallback((path) => {
    navigate(path);
  }, [navigate]);

  // Memoized danh sách phòng để tránh re-render không cần thiết
  const phongList = useMemo(() => phongs, [phongs]);

  if (loading) return <div className="spinner" />;

  return (
    <div className="container page-wrapper">
      <div className="page-title-row">
        <h1 className="section-title" style={{ marginBottom: 0 }}>Quản lý phòng</h1>
        <Link to="/tao-phong" className="btn btn-primary">Thêm phòng mới</Link>
      </div>

      {phongList.length === 0 ? (
        <div className="empty-state card">
          <div className="card-body">
            <div className="empty-state-icon">🏠</div>
            <p>Bạn chưa có phòng nào. <Link to="/tao-phong">Tạo phòng ngay</Link></p>
          </div>
        </div>
      ) : (
        <div className="phong-manage-list">
          {phongList.map(phong => (
            <RoomCard
              key={phong.maPhong}
              phong={phong}
              selectedPhong={selectedPhong}
              yeuCaus={yeuCaus}
              memberMenu={memberMenu}
              deletingPhongId={deletingPhongId}
              onToggleYeuCau={handleToggleYeuCau}
              onDeletePhong={handleDeletePhong}
              onChangeStatus={handleDoiTrangThai}
              onDeleteMember={handleXoaThanhVien}
              onOpenMemberMenu={handleOpenMemberMenu}
              onChiaTuDong={handleChiaTuDong}
              onNavigate={handleNavigate}
            />
          ))}
        </div>
      )}

      {/* Phần Phòng tôi tham gia */}
      <div className="card" style={{ marginTop: 28 }}>
        <div className="card-header">Phòng tôi tham gia</div>
        <div className="card-body">
          {phongThamGia.length === 0 ? (
            <div className="member-empty">Bạn chưa tham gia phòng nào.</div>
          ) : (
            <div className="joined-room-list">
              {phongThamGia.map(phong => (
                <div key={phong.maPhong} className="joined-room-item">
                  <div>
                    <strong>{phong.title}</strong>
                    <div className="phong-manage-subtitle">
                      {buildPhongAddress(phong)} · {fmt(phong.giaTien)}/thang
                    </div>
                  </div>
                  <button 
                    className="btn btn-outline btn-sm" 
                    onClick={() => handleNavigate(`/phong/${phong.maPhong}`)}
                  >
                    Xem chi tiết phòng
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
